html:
{%- set company = frappe.get_doc("Company", doc.company) -%}
{%- set campaign_label = frappe.db.get_value("Donation Campaign", doc.campaign, "campaign_name") or doc.campaign -%}
{%- set address_name = frappe.db.get_value("Dynamic Link", {"link_doctype": "Company", "link_name": doc.company, "parenttype": "Address"}, "parent") -%}
{%- set address = frappe.db.get_value("Address", address_name, ["address_line1", "address_line2", "city", "state", "pincode", "country"], as_dict=True) if address_name else None -%}
{%- set donor = frappe.get_doc("Donor", doc.donor) -%}
<div class="donation-receipt">
  <style>
    .donation-receipt { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; color: #1f2937; max-width: 720px; margin: 0 auto; }
    .donation-receipt .org { text-align: center; margin-bottom: 24px; padding-bottom: 16px; border-bottom: 2px solid #1f2937; }
    .donation-receipt .org .name { font-size: 22px; font-weight: 700; }
    .donation-receipt .org .addr { font-size: 12px; color: #6b7280; margin-top: 6px; line-height: 1.5; }
    .donation-receipt h1 { text-align: center; font-size: 16px; letter-spacing: 0.15em; text-transform: uppercase; color: #374151; margin: 24px 0 16px; }
    .donation-receipt .row { display: flex; justify-content: space-between; padding: 6px 0; font-size: 13px; border-bottom: 1px solid #f3f4f6; }
    .donation-receipt .row .label { color: #6b7280; text-transform: uppercase; font-size: 11px; letter-spacing: 0.4px; }
    .donation-receipt .row .value { font-weight: 600; }
    .donation-receipt h2 { font-size: 11px; text-transform: uppercase; letter-spacing: 0.4px; color: #6b7280; margin: 20px 0 4px; }
    .donation-receipt .amount { font-size: 28px; font-weight: 700; text-align: center; margin: 24px 0; padding: 20px; background: #f9fafb; border-radius: 6px; }
    .donation-receipt .notice { font-size: 12px; color: #4b5563; margin-top: 28px; padding-top: 12px; border-top: 1px solid #e5e7eb; line-height: 1.6; }
  </style>

  <div class="org">
    <div class="name">{{ company.company_name }}</div>
    {% if address %}
    <div class="addr">
      {{ address.address_line1 or "" }}{% if address.address_line2 %}, {{ address.address_line2 }}{% endif %}
      {% if address.city %}<br>{{ address.city }}{% if address.state %}, {{ address.state }}{% endif %}{% if address.pincode %} {{ address.pincode }}{% endif %}{% endif %}
      {% if address.country %}<br>{{ address.country }}{% endif %}
    </div>
    {% endif %}
  </div>

  <h1>{{ _("Official Donation Receipt") }}</h1>

  <div class="row"><span class="label">{{ _("Receipt Number") }}</span><span class="value">{{ doc.name }}</span></div>
  <div class="row"><span class="label">{{ _("Issued") }}</span><span class="value">{{ frappe.utils.formatdate(frappe.utils.nowdate()) }}</span></div>
  <div class="row"><span class="label">{{ _("Donation Date") }}</span><span class="value">{{ frappe.utils.formatdate(doc.donation_date) }}</span></div>

  <h2>{{ _("Donor") }}</h2>
  <div class="row"><span class="label">{{ _("Name") }}</span><span class="value">{{ donor.donor_name }}</span></div>
  <div class="row"><span class="label">{{ _("Email") }}</span><span class="value">{{ donor.email }}</span></div>

  <h2>{{ _("Gift") }}</h2>
  <div class="row"><span class="label">{{ _("Campaign") }}</span><span class="value">{{ campaign_label }}</span></div>
  <div class="row"><span class="label">{{ _("Frequency") }}</span><span class="value">{{ doc.frequency }}</span></div>

  {%- if doc.cover_fees and doc.fee_recovered -%}
  <div class="amount">{{ frappe.utils.fmt_money((doc.amount or 0) + (doc.fee_recovered or 0), currency=doc.currency or "USD") }}</div>
  <div class="row"><span class="label">{{ _("Donation") }}</span><span class="value">{{ frappe.utils.fmt_money(doc.amount, currency=doc.currency or "USD") }}</span></div>
  <div class="row"><span class="label">{{ _("Transaction Fees Covered") }}</span><span class="value">{{ frappe.utils.fmt_money(doc.fee_recovered, currency=doc.currency or "USD") }}</span></div>
  <div class="row"><span class="label">{{ _("Tax-Deductible Amount") }}</span><span class="value">{{ frappe.utils.fmt_money(doc.amount, currency=doc.currency or "USD") }}</span></div>
  {%- else -%}
  <div class="amount">{{ frappe.utils.fmt_money(doc.amount, currency=doc.currency or "USD") }}</div>
  {%- endif -%}

  <div class="notice">
    <p>{{ _("No goods or services were provided in exchange for this contribution. This donation is tax-deductible to the extent allowed by law. Please retain this receipt for your records.") }}</p>
    {%- if doc.cover_fees and doc.fee_recovered -%}
    <p>{{ _("The transaction-fee surcharge shown above is not tax-deductible.") }}</p>
    {%- endif -%}
    <p>{{ _("Thank you for your generous support of {0}.").format(company.company_name) }}</p>
  </div>
</div>
